(() => {
  const IMAGE_DATA = {'assets/zinergi-buddha-mark.png':'data:image/png;base64,','assets/mieke-hero.webp':'data:image/webp;base64,','assets/voeding.webp':'data:image/webp;base64,','assets/ademwerk.webp':'data:image/webp;base64,','assets/systemisch.webp':'data:image/webp;base64,','assets/products/biotica-avena.webp':'data:image/webp;base64,','assets/products/fiber-avena.webp':'data:image/webp;base64,','assets/products/magnesium-avena.webp':'data:image/webp;base64,','assets/products/multi-avena.webp':'data:image/webp;base64,','assets/products/leaky.webp':'data:image/webp;base64,','assets/products/darmpakket.webp':'data:image/webp;base64,','assets/products/hormoontest.webp':'data:image/webp;base64,','assets/products/consult.webp':'data:image/webp;base64,','assets/products/resetdarmen.webp':'data:image/webp;base64,','assets/products/ademreset.webp':'data:image/webp;base64,','assets/products/cacao.webp':'data:image/webp;base64,','assets/products/familie.webp':'data:image/webp;base64,'};
  const replaceImage = (img) => {
    const key = (img.getAttribute('src') || '').split('?')[0].replace(/^\.\//, '');
    if (IMAGE_DATA[key] && img.src !== IMAGE_DATA[key]) img.src = IMAGE_DATA[key];
  };
  const refresh = () => document.querySelectorAll('img').forEach(replaceImage);
  document.documentElement.style.setProperty('--buddha-logo', `url("${IMAGE_DATA['assets/zinergi-buddha-mark.png']}")`);
  const hero = document.querySelector('.hero-image');
  if (hero) hero.style.backgroundImage = `url("${IMAGE_DATA['assets/mieke-hero.webp']}")`;
  const portrait = document.querySelector('.mieke-photo');
  if (portrait) portrait.style.backgroundImage = `linear-gradient(180deg,rgba(36,53,45,.03),rgba(36,53,45,.18)),url("${IMAGE_DATA['assets/mieke-hero.webp']}")`;
  refresh();
  new MutationObserver(refresh).observe(document.body, {childList:true, subtree:true});
})();
